    905, 911, 917, 923, 929, 935, 941, 947, 953, 959, 965, 971 ; 
    temperature = 
    9, 10.5, 12, 13.5, 15, 16.5, 18, 19.5, 21, 22.5, 24, 25.5, 
    9.25, 10.75, 12.25, 13.75, 15.25, 16.75, 18.25, 19.75, 21.25, 22.75, 24.25, 
