对于上面的数据，就是 
latitude = 25，longitude = -125时，pressure = 900，temperature = 9; 
latitude = 25，longitude = -120时，pressure = 906，temperature = 10.5; 
以此类推。

根据文件格式进行多维解析，主要是copyToNDJavaArray()和copyTo1DJavaArray();

    // Open the file. The ReadOnly parameter tells netCDF we want
    // read-only access to the file.
    NetcdfFile dataFile = null;
    String filename = "D://mqpf_20181108_1715.nc";
    // Open the file.
    try {

    	dataFile = NetcdfFile.open(filename, null);

    	// Retrieve the variable named "data"
    	Variable v_time = dataFile.findVariable("time");
    	Variable v_timePhase = dataFile.findVariable("timePhase");
    	Variable v_lat = dataFile.findVariable("lat");
    	Variable v_lon = dataFile.findVariable("lon");
    	Variable v_level = dataFile.findVariable("level");
    	Variable qpf_ml = dataFile.findVariable("qpf_ml");

    	if (v_time == null) {
    		System.out.println("Cant find Variable v_time");
    		return;
    	}
    	if (v_timePhase == null) {
    		System.out.println("Cant find Variable v_timePhase");
    		return;
    	}
    	if (v_lat == null) {
    		System.out.println("Cant find Variable v_lat");
    		return;
    	}
    	if (v_lon == null) {
    		System.out.println("Cant find Variable v_lon");
    		return;
    	}
    	if (v_level == null) {
    		System.out.println("Cant find Variable v_level");
    		return;
    	}

    	int[] length = qpf_ml.getShape();
    	float[][][] data = (float[][][]) qpf_ml.read().copyToNDJavaArray();
    	for (int k = 0; k < length[0]; k++) {
    		for (int j = 0; j < length[1]; j++) {
    			for (int i = 0; i < length[2]; i++) {
    				if (data[k][j][i] > 0)
    					System.out.println(data[k][j][i]);
    			}
    		}
    	}

    	// The file is closed no matter what by putting inside a try/catch block.
    } catch (java.io.IOException e) {
    	e.printStackTrace();

    } finally {
    	if (dataFile != null)
    		try {
    			dataFile.close();
    		} catch (IOException ioe) {
    			ioe.printStackTrace();
    		}
    }

    System.out.println("*** SUCCESS reading example file simple_xy.nc!");

